import React, { useEffect, useRef, useState } from 'react';
import { Mail, Camera, Clock, Calendar } from 'lucide-react';

const playlist = [
  '/audio/marriage.mp3',
  '/audio/audio1.mp3',
  '/audio/audio2.mp3',
];

const HomePage: React.FC = () => {
  const audioRef = useRef<HTMLAudioElement>(null);
  const [playing, setPlaying] = useState(false);
  const [visible, setVisible] = useState(false);
  const [currentTrack, setCurrentTrack] = useState(0);

  useEffect(() => {
    setTimeout(() => setVisible(true), 200);
  }, []);

  const toggleAudio = () => {
    if (!audioRef.current) return;

    const nextTrack = (currentTrack + 1) % playlist.length;
    setCurrentTrack(nextTrack);

    setTimeout(() => {
      audioRef.current?.play().catch(() => {});
      setPlaying(true);
    }, 120);
  };

  const scrollTo = (id: string) => {
    document.getElementById(id)?.scrollIntoView({ behavior: 'smooth' });
  };

  const FloatingPetal = ({ style }: { style: React.CSSProperties }) => (
    <div
      style={{
        position: 'absolute',
        fontSize: 18,
        animation: 'petalFall 8s linear infinite',
        pointerEvents: 'none',
        ...style,
      }}
    >
      🌸
    </div>
  );

  return (
    <section
      id="home"
      style={{
        minHeight: '100vh',
        background:
          'linear-gradient(160deg, #1a0500 0%, #3d0c02 25%, #5c1204 50%, #3d0c02 75%, #1a0500 100%)',
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        position: 'relative',
        overflow: 'hidden',
        padding: '60px 20px',
      }}
    >
      {/* Audio */}
      <audio ref={audioRef} src={playlist[currentTrack]} preload="auto" />

      {/* Floating petals */}
      {[...Array(12)].map((_, i) => (
        <FloatingPetal
          key={i}
          style={{
            left: `${(i * 8.3) % 100}%`,
            top: `-5%`,
            animationDelay: `${i * 0.7}s`,
            animationDuration: `${6 + (i % 4)}s`,
            fontSize: 14 + (i % 3) * 6,
            opacity: 0.6,
          }}
        />
      ))}

      {/* Rangoli background */}
      <div style={{ position: 'absolute', opacity: 0.06, pointerEvents: 'none' }}>
        <svg width="600" height="600" viewBox="0 0 600 600">
          {[...Array(12)].map((_, i) => {
            const angle = (i / 12) * Math.PI * 2;
            const x = 300 + Math.cos(angle) * 220;
            const y = 300 + Math.sin(angle) * 220;
            return (
              <g key={i}>
                <line x1="300" y1="300" x2={x} y2={y} stroke="#FFD700" strokeWidth="1.5" />
                <circle cx={x} cy={y} r="12" fill="none" stroke="#FFD700" strokeWidth="2" />
                <circle cx={x} cy={y} r="5" fill="#FFD700" />
              </g>
            );
          })}
        </svg>
      </div>

      {/* Main content */}
      <div
        style={{
          textAlign: 'center',
          maxWidth: 700,
          position: 'relative',
          zIndex: 1,
          opacity: visible ? 1 : 0,
          transform: visible ? 'translateY(0)' : 'translateY(30px)',
          transition: 'all 1.4s cubic-bezier(0.16, 1, 0.3, 1)',
        }}
      >
        <div
          style={{
            fontFamily: "'Noto Serif Tamil', serif",
            fontSize: 13,
            color: '#FFA07A',
            letterSpacing: '0.25em',
            marginBottom: 16,
          }}
        >
          ❁ அழைக்கின்றோம் ❁
        </div>

        <div
          style={{
            fontFamily: 'serif',
            fontSize: 'clamp(3rem, 10vw, 6rem)',
            color: '#FFD700',
            animation: 'omPulse 3s ease-in-out infinite',
          }}
        >
          ॐ
        </div>

        <h1
          style={{
            fontFamily: "'Cormorant Garamond', serif",
            fontSize: 'clamp(2.8rem, 10vw, 5.5rem)',
            color: '#FFD700',
            fontStyle: 'italic',
            fontWeight: 300,
            marginBottom: 12,
          }}
        >
          Nagamani <br /> & <br /> Kirthika
        </h1>

        <div style={{ color: '#FFA07A', marginBottom: 40 }}>
          பிப்ரவரி 22, 2026 · குலமங்கலம்
        </div>

        <div style={{ display: 'flex', gap: 16, justifyContent: 'center' }}>
          <button onClick={() => scrollTo('invitation')}>
            <Mail size={18} /> Invitation
          </button>
          <button onClick={() => scrollTo('gallery')}>
            <Camera size={18} /> Gallery
          </button>
          <button onClick={() => scrollTo('countdown')}>
            <Clock size={18} /> Countdown
          </button>
        </div>

        <div style={{ marginTop: 30, color: '#FFD700' }}>
          <Calendar size={16} /> February 22, 2026 · Kulamangalam
        </div>
      </div>

      {/* Audio control */}
      <button
        onClick={toggleAudio}
        style={{
          position: 'fixed',
          bottom: 28,
          right: 28,
          width: 52,
          height: 52,
          borderRadius: '50%',
          background: 'linear-gradient(135deg, #8B0000, #cc2200)',
          color: '#FFD700',
          fontSize: 20,
          cursor: 'pointer',
          animation: playing ? 'musicPulse 2s infinite' : 'none',
        }}
      >
        🎶
      </button>

      <style>{`
        @keyframes petalFall {
          0% { transform: translateY(-20px); opacity: 0; }
          100% { transform: translateY(110vh); opacity: 0; }
        }
        @keyframes omPulse {
          0%,100% { transform: scale(1); }
          50% { transform: scale(1.06); }
        }
        @keyframes musicPulse {
          0%,100% { box-shadow: 0 0 0 0 rgba(255,107,53,.4); }
          50% { box-shadow: 0 0 0 12px rgba(255,107,53,0); }
        }
      `}</style>
    </section>
  );
};

export default HomePage;
